<?php require_once __DIR__.'/../config.php'; require_once __DIR__.'/../includes/Database.php'; require_once __DIR__.'/../includes/RedisClient.php'; require_once __DIR__.'/../includes/Session.php'; require_once __DIR__.'/../includes/Auth.php'; require_once __DIR__.'/../includes/Monitor.php'; Session::start();Auth::require(); $db=Database::getInstance();$msg='';$err=''; if($_SERVER['REQUEST_METHOD']==='POST'){if(!Auth::validateCsrf()){$err='安全验证失败。';}else{$a=$_POST['action']??'';if($a==='add'||$a==='edit'){$n=trim($_POST['name']??'');$u=trim($_POST['url']??'');$cp=trim($_POST['check_path']??'/');$es=(int)($_POST['expected_status']??200);$ci=(int)($_POST['check_interval']??300);$to=(int)($_POST['timeout']??10);$cs=isset($_POST['check_ssl'])?1:0;$cd=isset($_POST['check_dns'])?1:0;$eb=trim($_POST['expected_body']??'');$do=(int)($_POST['display_order']??0);$ia=isset($_POST['is_active'])?1:0;$tg=trim($_POST['tags']??'');$nt=trim($_POST['notes']??'');if(empty($n)||empty($u)){$err='站点名称和URL不能为空。';}elseif(!filter_var($u,FILTER_VALIDATE_URL)){$err='请输入有效的URL。';}else{$d=['name'=>$n,'url'=>$u,'check_path'=>$cp,'expected_status'=>$es,'check_interval'=>$ci,'timeout'=>$to,'check_ssl'=>$cs,'check_dns'=>$cd,'expected_body'=>$eb,'display_order'=>$do,'is_active'=>$ia,'tags'=>$tg,'notes'=>$nt];try{if($a==='add'){$db->insert('sites',$d);$msg='站点添加成功。';}else{$id=(int)($_POST['id']??0);$db->update('sites',$d,'id=?',[$id]);$msg='站点更新成功。';}}catch(Exception $e){$err='操作失败: '.$e->getMessage();}}}elseif($a==='delete'){$id=(int)($_POST['id']??0);$db->delete('sites','id=?',[$id]);$msg='站点已删除。';}elseif($a==='check_now'){$id=(int)($_POST['id']??0);$s=$db->fetch("SELECT * FROM `sites` WHERE id=?",[$id]);if($s){$r=Monitor::checkSite($s);Monitor::saveResult($id,$r);$msg='检测完成: '.($r['status']==='ok'?'在线':'离线');}}elseif($a==='toggle'){$id=(int)($_POST['id']??0);$s=$db->fetch("SELECT is_active FROM `sites` WHERE id=?",[$id]);$db->update('sites',['is_active'=>$s['is_active']?0:1],'id=?',[$id]);$msg=$s['is_active']?'站点已停用。':'站点已启用。';}}} $sites=$db->fetchAll("SELECT * FROM `sites` ORDER BY display_order ASC, name ASC");$es=null;$ei=$_GET['edit']??null;if($ei)$es=$db->fetch("SELECT * FROM `sites` WHERE id=?",[(int)$ei]);$u=Auth::user();?><!DOCTYPE html><html lang="zh-CN"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1.0"><title>站点管理 - <?php echo APP_NAME;?></title><link href="https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700&display=swap" rel="stylesheet"><link href="https://fonts.googleapis.com/icon?family=Material+Icons" rel="stylesheet"><link href="/assets/css/admin.css" rel="stylesheet"></head><body><div class="admin-layout"><?php include __DIR__.'/sidebar.php';?><main class="main-content"><div class="top-bar"><h2>站点管理</h2><div class="top-bar-right"><span class="user-info"><span class="material-icons">person</span><?php echo e($u['username']);?></span></div></div><?php if($msg):?><div class="alert alert-success"><?php echo e($msg);?></div><?php endif;?><?php if($err):?><div class="alert alert-danger"><?php echo e($err);?></div><?php endif;?><div class="card"><div class="card-header"><h3><?php echo $es?'编辑站点':'添加新站点';?></h3><?php if($es):?><a href="/admin/sites.php" class="btn-sm">取消</a><?php endif;?></div><div class="card-body"><form method="POST" class="form"><input type="hidden" name="csrf_token" value="<?php echo e(Auth::csrfToken());?>"><input type="hidden" name="action" value="<?php echo $es?'edit':'add';?>"><?php if($es):?><input type="hidden" name="id" value="<?php echo $es['id'];?>"><?php endif;?><div class="form-row"><div class="form-group"><label>站点名称 *</label><input type="text" name="name" value="<?php echo e($es['name']??'');?>" required></div><div class="form-group"><label>URL *</label><input type="url" name="url" value="<?php echo e($es['url']??'');?>" required></div></div><div class="form-row"><div class="form-group"><label>检测路径</label><input type="text" name="check_path" value="<?php echo e($es['check_path']??'/');?>"></div><div class="form-group"><label>期望状态码</label><input type="number" name="expected_status" value="<?php echo e((string)($es['expected_status']??200));?>"></div></div><div class="form-row"><div class="form-group"><label>检测间隔(秒)</label><input type="number" name="check_interval" value="<?php echo e((string)($es['check_interval']??300));?>" min="60"></div><div class="form-group"><label>超时(秒)</label><input type="number" name="timeout" value="<?php echo e((string)($es['timeout']??10));?>" min="1" max="60"></div></div><div class="form-row"><div class="form-group"><label>期望响应内容</label><input type="text" name="expected_body" value="<?php echo e($es['expected_body']??'');?>"></div><div class="form-group"><label>排序</label><input type="number" name="display_order" value="<?php echo e((string)($es['display_order']??0));?>"></div></div><div class="form-row"><div class="form-group"><label>标签</label><input type="text" name="tags" value="<?php echo e($es['tags']??'');?>"></div><div class="form-group"><label>备注</label><input type="text" name="notes" value="<?php echo e($es['notes']??'');?>"></div></div><div class="form-row form-checks"><label class="checkbox-label"><input type="checkbox" name="check_ssl" <?php echo (!isset($es)||$es['check_ssl'])?'checked':'';?>> 检测SSL</label><label class="checkbox-label"><input type="checkbox" name="check_dns" <?php echo (!isset($es)||$es['check_dns'])?'checked':'';?>> 检测DNS</label><label class="checkbox-label"><input type="checkbox" name="is_active" <?php echo (!isset($es)||$es['is_active'])?'checked':'';?>> 启用</label></div><button type="submit" class="btn btn-primary"><?php echo $es?'更新站点':'添加站点';?></button></form></div></div><div class="card"><div class="card-header"><h3>站点列表 (<?php echo count($sites);?>)</h3></div><div class="card-body"><?php if(empty($sites)):?><p class="text-muted">暂无站点</p><?php else:?><table class="table"><thead><tr><th>名称</th><th>URL</th><th>状态</th><th>间隔</th><th>操作</th></tr></thead><tbody><?php foreach($sites as $s):?><tr><td><?php echo e($s['name']);?><?php if(!$s['is_active']):?> <span class="badge badge-secondary">停用</span><?php endif;?></td><td><a href="<?php echo e($s['url']);?>" target="_blank"><?php echo e($s['url']);?></a></td><td><span class="badge badge-<?php echo $s['is_active']?'success':'secondary';?>"><?php echo $s['is_active']?'启用':'停用';?></span></td><td><?php echo $s['check_interval'];?>s</td><td class="actions"><a href="/admin/sites.php?edit=<?php echo $s['id'];?>" class="btn-sm">编辑</a><form method="POST" style="display:inline" onsubmit="return confirm('立即检测？');"><input type="hidden" name="csrf_token" value="<?php echo e(Auth::csrfToken());?>"><input type="hidden" name="action" value="check_now"><input type="hidden" name="id" value="<?php echo $s['id'];?>"><button type="submit" class="btn-sm btn-info">检测</button></form><form method="POST" style="display:inline"><input type="hidden" name="csrf_token" value="<?php echo e(Auth::csrfToken());?>"><input type="hidden" name="action" value="toggle"><input type="hidden" name="id" value="<?php echo $s['id'];?>"><button type="submit" class="btn-sm btn-warning"><?php echo $s['is_active']?'停用':'启用';?></button></form><form method="POST" style="display:inline" onsubmit="return confirm('确定删除？');"><input type="hidden" name="csrf_token" value="<?php echo e(Auth::csrfToken());?>"><input type="hidden" name="action" value="delete"><input type="hidden" name="id" value="<?php echo $s['id'];?>"><button type="submit" class="btn-sm btn-danger">删除</button></form></td></tr><?php endforeach;?></tbody></table><?php endif;?></div></div></main></div></body></html>